if n <= 0:
    raise ValueError("n must be a positive integer")

def is_prime(x: int) -> bool:
    if x < 2:
        return False
    if x in (2, 3):
        return True
    if x % 2 == 0 or x % 3 == 0:
        return False
    i = 5
    step = 2
    while i * i <= x:
        if x % i == 0:
            return False
        i += step
        step = 6 - step
    return True

count = 0
a, b = 0, 1
while True:
    a, b = b, a + b
    if is_prime(a):
        count += 1
        if count == n:
            return a
